import os
import re

# Padrão para detectar caracteres japoneses e chineses
pattern = re.compile(r'[\u4e00-\u9fff\u3040-\u309f\u30a0-\u30ff]')

found = []
for root, dirs, files in os.walk('.'):
    for file in files:
        if file.endswith(('.md', '.json', '.txt')):
            filepath = os.path.join(root, file)
            try:
                with open(filepath, 'r', encoding='utf-8') as f:
                    content = f.read()
                    if pattern.search(content):
                        # Contar ocorrências
                        matches = pattern.findall(content)
                        found.append(f"{filepath}: {len(matches)} caracteres")
            except:
                pass

if found:
    for item in found[:50]:  # Limitar a 50 resultados
        print(item)
else:
    print("Nenhum caractere japonês ou chinês encontrado.")
EOF

